#! /usr/bin/env bash

set -eo pipefail

THIS_DIR="$(dirname "$(readlink -f "$0")")"

CUTLASS_ADDITIONAL_CMAKE_ARGS="${CUTLASS_ADDITIONAL_CMAKE_ARGS} -DCUTLASS_NVCC_ARCHS='80'"
CUTLASS_ADDITIONAL_CMAKE_ARGS="${CUTLASS_ADDITIONAL_CMAKE_ARGS} -DCUTLASS_ENABLE_INTERNAL_NVVM=ON"
CUTLASS_ADDITIONAL_CMAKE_ARGS="${CUTLASS_ADDITIONAL_CMAKE_ARGS} -DCUTLASS_ENABLE_EXTENDED_PTX=ON"
CUTLASS_ADDITIONAL_CMAKE_ARGS="${CUTLASS_ADDITIONAL_CMAKE_ARGS} -DCUTLASS_ENABLE_CUBLAS=OFF"
CUTLASS_ADDITIONAL_CMAKE_ARGS="${CUTLASS_ADDITIONAL_CMAKE_ARGS} -DCUTLASS_ENABLE_CUDNN=OFF"

CUTLASS_ADDITIONAL_CMAKE_ARGS="${CUTLASS_ADDITIONAL_CMAKE_ARGS} -DCUTLASS_ENABLE_F16C=0"

CUTLASS_ADDITIONAL_CMAKE_ARGS=${CUTLASS_ADDITIONAL_CMAKE_ARGS} ${SHELL} ${THIS_DIR}/build.linux.lsf.fast.sh "$@"
